```c
#include <stdio.h>

int gcd(int a, int b) {
    while (a != 0 && b != 0) {
        int t = a % b;
        a = b;
        b = t;
    }
    return a;
}

int main() {
    int a, b, x, y;
    scanf("%d %d %d %d", &a, &b, &x, &y);
    int tmp = gcd(x, y);
    x /= tmp;
    y /= tmp;
    int ans = (a / x < b / y) ? a / x : b / y;
    printf("%d\n", ans);
    return 0;
}
```

